#include "cJSON.h"
#include "lodepng.h"

#include <algorithm>
#include <cstdint>
#include <cstdlib>
#include <fstream>
#include <iostream>
#include <iterator>
#include <stdexcept>
#include <string>
#include <vector>

namespace {

std::string read_file(const char* path) {
    std::ifstream in(path, std::ios::binary);
    if (!in) {
        throw std::runtime_error("failed to open file");
    }
    return std::string(std::istreambuf_iterator<char>(in), std::istreambuf_iterator<char>());
}

int json_int(cJSON* root, const char* name) {
    cJSON* item = cJSON_GetObjectItemCaseSensitive(root, name);
    if (!cJSON_IsNumber(item)) {
        throw std::runtime_error("missing numeric field");
    }
    return item->valueint;
}

std::vector<float> json_float_array(cJSON* root, const char* name, int expected_size) {
    cJSON* arr = cJSON_GetObjectItemCaseSensitive(root, name);
    if (!cJSON_IsArray(arr) || cJSON_GetArraySize(arr) != expected_size) {
        throw std::runtime_error("missing or incorrectly sized weight array");
    }

    std::vector<float> out;
    out.reserve(expected_size);
    cJSON* value = nullptr;
    cJSON_ArrayForEach(value, arr) {
        if (!cJSON_IsNumber(value)) {
            throw std::runtime_error("non-numeric weight value");
        }
        out.push_back(static_cast<float>(value->valuedouble));
    }
    return out;
}

struct Model {
    int input_dim = 0;
    int hidden_dim = 0;
    int num_classes = 0;
    std::vector<float> input_weight;
    std::vector<float> input_bias;
    std::vector<float> hidden_weight;
    std::vector<float> hidden_bias;
    std::vector<float> output_weight;
    std::vector<float> output_bias;
};

Model load_model(const char* weights_path) {
    std::string text = read_file(weights_path);
    cJSON* root = cJSON_ParseWithLength(text.data(), text.size());
    if (root == nullptr) {
        throw std::runtime_error("failed to parse weights json");
    }

    try {
        Model model;
        model.input_dim = json_int(root, "input_dim");
        model.hidden_dim = json_int(root, "hidden_dim");
        model.num_classes = json_int(root, "num_classes");

        model.input_weight = json_float_array(root, "input_layer.weight", model.hidden_dim * model.input_dim);
        model.input_bias = json_float_array(root, "input_layer.bias", model.hidden_dim);
        model.hidden_weight = json_float_array(root, "hidden_layer.weight", model.hidden_dim * model.hidden_dim);
        model.hidden_bias = json_float_array(root, "hidden_layer.bias", model.hidden_dim);
        model.output_weight = json_float_array(root, "output_layer.weight", model.num_classes * model.hidden_dim);
        model.output_bias = json_float_array(root, "output_layer.bias", model.num_classes);

        cJSON_Delete(root);
        return model;
    } catch (...) {
        cJSON_Delete(root);
        throw;
    }
}

std::vector<float> load_image(const char* image_path, int input_dim) {
    std::vector<unsigned char> pixels;
    unsigned width = 0;
    unsigned height = 0;
    unsigned error = lodepng::decode(pixels, width, height, image_path, LCT_RGBA, 8);
    if (error != 0) {
        throw std::runtime_error("failed to decode png");
    }
    if (width * height != static_cast<unsigned>(input_dim)) {
        throw std::runtime_error("image dimensions do not match model input");
    }

    std::vector<float> input;
    input.reserve(input_dim);
    for (unsigned i = 0; i < width * height; ++i) {
        const unsigned char r = pixels[4 * i + 0];
        const unsigned char g = pixels[4 * i + 1];
        const unsigned char b = pixels[4 * i + 2];
        const unsigned char a = pixels[4 * i + 3];
        const float luminance = (0.299f * r + 0.587f * g + 0.114f * b) * (a / 255.0f);
        input.push_back(luminance / 255.0f);
    }
    return input;
}

void linear_relu(
    const std::vector<float>& input,
    const std::vector<float>& weight,
    const std::vector<float>& bias,
    int out_dim,
    int in_dim,
    std::vector<float>& output
) {
    output.assign(out_dim, 0.0f);
    for (int row = 0; row < out_dim; ++row) {
        float sum = bias[row];
        const float* row_weight = &weight[row * in_dim];
        for (int col = 0; col < in_dim; ++col) {
            sum += row_weight[col] * input[col];
        }
        output[row] = std::max(0.0f, sum);
    }
}

int predict(const Model& model, const std::vector<float>& input) {
    std::vector<float> hidden1;
    std::vector<float> hidden2;
    linear_relu(input, model.input_weight, model.input_bias, model.hidden_dim, model.input_dim, hidden1);
    linear_relu(hidden1, model.hidden_weight, model.hidden_bias, model.hidden_dim, model.hidden_dim, hidden2);

    int best_digit = 0;
    float best_score = model.output_bias[0];
    for (int col = 0; col < model.hidden_dim; ++col) {
        best_score += model.output_weight[col] * hidden2[col];
    }

    for (int digit = 1; digit < model.num_classes; ++digit) {
        float score = model.output_bias[digit];
        const float* row_weight = &model.output_weight[digit * model.hidden_dim];
        for (int col = 0; col < model.hidden_dim; ++col) {
            score += row_weight[col] * hidden2[col];
        }
        if (score > best_score) {
            best_score = score;
            best_digit = digit;
        }
    }
    return best_digit;
}

}  // namespace

int main(int argc, char** argv) {
    if (argc != 3) {
        return 1;
    }

    try {
        Model model = load_model(argv[1]);
        std::vector<float> input = load_image(argv[2], model.input_dim);
        std::cout << predict(model, input) << '\n';
    } catch (const std::exception&) {
        return 1;
    }
    return 0;
}
